set-header.value:
@{
                        var xff = context.Request.Headers.GetValueOrDefault("X-Forwarded-For", "").Trim();
                        // X-Forwarded-For may be a comma-separated list; take the first (original) IP.
                        return xff.Contains(",") ? xff.Split(',')[0].Trim() : xff;
                    }

@{
                            var retryAfter = context.Response.Headers.GetValueOrDefault("Retry-After", "30");
                            int retryAfterSeconds;
                            if (System.Int32.TryParse(retryAfter, out retryAfterSeconds))
                            {
                                return System.Math.Max(0, retryAfterSeconds * 1000).ToString();
                            }
                            return "30000";
                        }

return-response.set-body:
@{
                        var retryAfter = context.Response.Headers.GetValueOrDefault("Retry-After", "30");
                        return new JObject(
                            new JProperty("error", new JObject(
                                new JProperty("code", "429"),
                                new JProperty("message", "Too Many Requests - Rate limit exceeded"),
                                new JProperty("retryAfter", retryAfter),
                                new JProperty("requestId", context.RequestId.ToString())
                            ))
                        ).ToString();
                    }

set-header.value:
@{
                            var retryAfter = context.Response.Headers.GetValueOrDefault("Retry-After", "60");
                            int retryAfterSeconds;
                            if (System.Int32.TryParse(retryAfter, out retryAfterSeconds))
                            {
                                return System.Math.Max(0, retryAfterSeconds * 1000).ToString();
                            }
                            return "60000";
                        }

return-response.set-body:
@{
                        var retryAfter = context.Response.Headers.GetValueOrDefault("Retry-After", "60");
                        return new JObject(
                            new JProperty("error", new JObject(
                                new JProperty("code", "429"),
                                new JProperty("message", "Too Many Requests - backend circuit breaker is open. Retry after the indicated period."),
                                new JProperty("retryAfter", retryAfter),
                                new JProperty("requestId", context.RequestId.ToString())
                            ))
                        ).ToString();
                    }

@{
                        var statusCode = context.Response.StatusCode.ToString();
                        var statusReason = context.Response.StatusReason ?? "Error";
                        // Scrub internal Azure hostnames from error reason text
                        statusReason = System.Text.RegularExpressions.Regex.Replace(
                            statusReason,
                            @"https?://[a-zA-Z0-9\-]+\.(cognitiveservices\.azure\.com|openai\.azure\.com|search\.windows\.net|blob\.core\.windows\.net|vault\.azure\.net|azure-api\.net)[^\s]*",
                            "[internal-service]");
                        return new JObject(
                            new JProperty("error", new JObject(
                                new JProperty("code", statusCode),
                                new JProperty("message", statusReason),
                                new JProperty("requestId", context.RequestId.ToString())
                            ))
                        ).ToString();
                    }
